"use client";

import {
  Cancel01Icon,
} from "@hugeicons/core-free-icons";
import { HugeiconsIcon } from "@hugeicons/react";
import { useForm } from "@tanstack/react-form";
import { useRouter } from "next/navigation";
import type { JSX, ReactNode } from "react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field";
import { Input } from "@/components/ui/input";
import { RequiredOptionalBadge } from "@/components/ui/required-optional-badge";
import { Textarea } from "@/components/ui/textarea";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import {
  type CourseBasicForm,
  CourseBasicFormProvider,
} from "@/app/(main)/courses/new/_components/course-basic-form-context";
import {
  courseBasicFormSchema,
  type CourseBasicFormValues,
  toCourseBasicSubmissionPayload,
} from "@/app/(main)/courses/new/_lib/course-form.schema";
import {
  createCourse,
  type CreateCourseErrorCode,
} from "@/app/(main)/courses/new/course-create.action";

const errorMessages: Record<CreateCourseErrorCode, string> = {
  SUBMIT_FAILED: "コースの作成に失敗しました。時間をおいて再度お試しください。",
  CONFLICT: "同じ Slug のコースが既に存在します。別の Slug を指定してください。",
  UNAUTHORIZED: "ログインが必要です。再度ログインしてください。",
};

const defaultValues: CourseBasicFormValues = {
  title: "",
  description: "",
  slug: "",
  tags: [],
  visibility: "public",
  categorySlug: "",
  categoryName: "",
};

export function CourseCreateForm({
  categorySelector,
}: {
  categorySelector: ReactNode;
}): JSX.Element {
  const router = useRouter();
  const isHydrated = useIsHydrated();
  const [submitError, setSubmitError] = useState<string | null>(null);

  const form = useForm({
    defaultValues,
    validators: {
      onBlur: courseBasicFormSchema,
      onSubmit: courseBasicFormSchema,
    },
    onSubmit: async ({ value }) => {
      setSubmitError(null);
      try {
        const response = await createCourse(
          toCourseBasicSubmissionPayload(value),
        );
        if (response.success) {
          router.push(`/courses/${response.courseId}/sections`);
        } else {
          setSubmitError(errorMessages[response.code]);
        }
      } catch {
        setSubmitError(errorMessages.SUBMIT_FAILED);
      }
    },
  });

  return (
    <CourseBasicFormProvider value={form}>
      <form
        onSubmit={(event) => {
          event.preventDefault();
          event.stopPropagation();
          form.handleSubmit();
        }}
        className="grid gap-10"
        noValidate
      >
        <section className="grid gap-6">
          <header className="grid gap-1">
            <h2 className="text-lg font-bold">基本情報</h2>
            <p className="text-sm text-muted-foreground">
              コース全体のメタ情報を入力します。下書きとして作成され、次の画面でセクション・トピックを入力します。
            </p>
          </header>

          <form.Field name="title">
            {(field) => {
              // フォーム全体スキーマで onBlur 検証するため、未 blur フィールドにもエラーが伝播する。
              // 触っていないフィールドを赤くしないよう isBlurred で表示判定をゲートする。
              const showError =
                field.state.meta.isBlurred && !field.state.meta.isValid;
              return (
                <Field data-invalid={showError}>
                  <FieldLabel htmlFor={field.name}>
                    コースタイトル
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={showError}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                  />
                  <FieldDescription>120 文字以内</FieldDescription>
                  <FieldError errors={showError ? field.state.meta.errors : []} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name="description">
            {(field) => {
              const showError =
                field.state.meta.isBlurred && !field.state.meta.isValid;
              return (
                <Field data-invalid={showError}>
                  <FieldLabel htmlFor={field.name}>
                    コース概要
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Textarea
                    id={field.name}
                    name={field.name}
                    aria-invalid={showError}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    className="h-32"
                    disabled={!isHydrated}
                  />
                  <FieldDescription>
                    対象者・学べる内容など。2000 文字以内
                  </FieldDescription>
                  <FieldError errors={showError ? field.state.meta.errors : []} />
                </Field>
              );
            }}
          </form.Field>

          <form.Field name="slug">
            {(field) => {
              const showError =
                field.state.meta.isBlurred && !field.state.meta.isValid;
              return (
                <Field data-invalid={showError}>
                  <FieldLabel htmlFor={field.name}>
                    コース Slug
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <Input
                    id={field.name}
                    name={field.name}
                    aria-invalid={showError}
                    value={field.state.value}
                    onChange={(event) => field.handleChange(event.target.value)}
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                    className="md:max-w-md"
                  />
                  <FieldDescription>
                    URL に使われる識別子。半角英数字とハイフンのみ
                  </FieldDescription>
                  <FieldError errors={showError ? field.state.meta.errors : []} />
                </Field>
              );
            }}
          </form.Field>

          {categorySelector}

          <form.Field name="visibility">
            {(field) => {
              const showError =
                field.state.meta.isBlurred && !field.state.meta.isValid;
              return (
                <Field data-invalid={showError}>
                  <FieldLabel htmlFor={field.name}>
                    公開範囲
                    <RequiredOptionalBadge required />
                  </FieldLabel>
                  <select
                    id={field.name}
                    name={field.name}
                    aria-invalid={showError}
                    value={field.state.value}
                    onChange={(event) =>
                      field.handleChange(
                        event.target.value as CourseBasicFormValues["visibility"],
                      )
                    }
                    onBlur={field.handleBlur}
                    disabled={!isHydrated}
                    className="h-9 w-full rounded-md border bg-transparent px-3 text-sm shadow-xs md:max-w-xs"
                  >
                    <option value="public">公開（誰でも閲覧可）</option>
                    <option value="private">非公開（自分のみ）</option>
                  </select>
                  <FieldError errors={showError ? field.state.meta.errors : []} />
                </Field>
              );
            }}
          </form.Field>

          <TagsField form={form} disabled={!isHydrated} />
        </section>

        {submitError && (
          <p role="alert" className="text-sm text-destructive">
            {submitError}
          </p>
        )}

        <form.Subscribe selector={(state) => [state.isSubmitting, state.isValid]}>
          {([isSubmitting, isValid]) => (
            <Button
              type="submit"
              disabled={!isHydrated || isSubmitting || !isValid}
              className="justify-self-end"
            >
              {isSubmitting ? "作成中..." : "コースを作成（下書きとして保存）"}
            </Button>
          )}
        </form.Subscribe>
      </form>
    </CourseBasicFormProvider>
  );
}

function TagsField({
  form,
  disabled,
}: {
  form: CourseBasicForm;
  disabled: boolean;
}): JSX.Element {
  const [draft, setDraft] = useState("");

  return (
    <form.Field name="tags" mode="array">
      {(tagsField) => {
        const tags = tagsField.state.value;
        const addTag = (): void => {
          const value = draft.trim();
          if (!value || tags.includes(value)) {
            setDraft("");
            return;
          }
          tagsField.pushValue(value);
          setDraft("");
        };
        // 配列フィールドは blur イベントを受けないため isTouched で判定する
        const showError =
          tagsField.state.meta.isTouched && !tagsField.state.meta.isValid;
        return (
          <Field data-invalid={showError}>
            <FieldLabel htmlFor="tags-input">
              タグ
              <RequiredOptionalBadge required={false} />
            </FieldLabel>
            <div className="flex flex-wrap gap-2">
              {tags.map((tag, index) => (
                <span
                  key={`${tag}-${index}`}
                  className="inline-flex items-center gap-1 rounded-full bg-secondary px-3 py-1 text-xs"
                >
                  {tag}
                  <button
                    type="button"
                    onClick={() => tagsField.removeValue(index)}
                    disabled={disabled}
                    className="text-muted-foreground hover:text-foreground"
                  >
                    <HugeiconsIcon icon={Cancel01Icon} className="size-3" />
                    <span className="sr-only">{tag} を削除</span>
                  </button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <Input
                id="tags-input"
                value={draft}
                onChange={(event) => setDraft(event.target.value)}
                onKeyDown={(event) => {
                  if (event.key === "Enter") {
                    event.preventDefault();
                    addTag();
                  }
                }}
                disabled={disabled}
              />
              <Button
                type="button"
                variant="outline"
                onClick={addTag}
                disabled={disabled}
              >
                追加
              </Button>
            </div>
            <FieldDescription>
              入力後 Enter または「追加」で追加。各 30 文字以内・最大 20 件
            </FieldDescription>
            <FieldError
              errors={showError ? tagsField.state.meta.errors : []}
            />
          </Field>
        );
      }}
    </form.Field>
  );
}

